/**
 * CloakSeed App Router
 * Main application entry point
 */

import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';
import { Menu, X, Shield, Settings, LogOut } from 'lucide-react';
import useCloakSeed from './hooks/useCloakSeed';

// Pages
import { CloakSeedLanding } from './components/CloakSeed/Landing';
import { CloakGenerator } from './components/CloakSeed/CloakGenerator';
import { CloakRestore } from './components/CloakSeed/CloakRestore';
import { ThemeSelector } from './components/CloakSeed/ThemeSelector';
import { CloakDisplay } from './components/CloakSeed/CloakDisplay';
import { PanicPhrase } from './components/CloakSeed/PanicPhrase';
import { Export } from './components/CloakSeed/Export';

function AppContent() {
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const cloakSeed = useCloakSeed();

  const handleStartApp = () => {
    if (!cloakSeed.cipher) {
      navigate('/create-cipher');
    } else {
      navigate('/generate');
    }
  };

  const handleReset = () => {
    if (confirm('This will delete all data. Continue?')) {
      cloakSeed.reset();
      navigate('/');
    }
  };

  return (
    <div className="min-h-screen bg-black text-white">
      {/* Navigation */}
      <nav className="bg-gray-900/50 border-b border-gray-800 sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-4 py-4 flex items-center justify-between">
          <Link to="/" className="flex items-center gap-2 font-bold text-lg">
            <Shield className="w-6 h-6 text-blue-400" />
            CloakSeed
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center gap-6">
            {cloakSeed.cipher && (
              <>
                <Link to="/generate" className="hover:text-blue-400 transition text-sm">
                  Generate
                </Link>
                <Link to="/restore" className="hover:text-blue-400 transition text-sm">
                  Restore
                </Link>
                <Link to="/panic" className="hover:text-blue-400 transition text-sm">
                  Panic
                </Link>
                <Link to="/export" className="hover:text-blue-400 transition text-sm">
                  Export
                </Link>
              </>
            )}
            <button
              onClick={handleReset}
              className="flex items-center gap-2 px-3 py-1 text-red-400 hover:text-red-300 transition text-sm"
            >
              <LogOut className="w-4 h-4" />
              Reset
            </button>
          </div>

          {/* Mobile Menu Toggle */}
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className="md:hidden"
          >
            {menuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>

        {/* Mobile Menu */}
        {menuOpen && (
          <div className="md:hidden border-t border-gray-800 bg-gray-800/50 p-4 space-y-2">
            {cloakSeed.cipher && (
              <>
                <Link to="/generate" className="block px-4 py-2 hover:bg-gray-700 rounded text-sm">
                  Generate
                </Link>
                <Link to="/restore" className="block px-4 py-2 hover:bg-gray-700 rounded text-sm">
                  Restore
                </Link>
                <Link to="/panic" className="block px-4 py-2 hover:bg-gray-700 rounded text-sm">
                  Panic Phrase
                </Link>
                <Link to="/export" className="block px-4 py-2 hover:bg-gray-700 rounded text-sm">
                  Export
                </Link>
                <button
                  onClick={handleReset}
                  className="block w-full text-left px-4 py-2 hover:bg-red-900/30 rounded text-red-400 text-sm"
                >
                  Reset All
                </button>
              </>
            )}
          </div>
        )}
      </nav>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        <Routes>
          <Route path="/" element={<CloakSeedLanding onStart={handleStartApp} />} />
          <Route
            path="/create-cipher"
            element={
              <CreateCipherPage
                cloakSeed={cloakSeed}
                onDone={() => navigate('/generate')}
              />
            }
          />
          <Route
            path="/generate"
            element={
              <GeneratePage
                cloakSeed={cloakSeed}
                onNavigate={navigate}
              />
            }
          />
          <Route
            path="/restore"
            element={
              <RestorePage
                cloakSeed={cloakSeed}
              />
            }
          />
          <Route
            path="/panic"
            element={
              <PanicPage
                cloakSeed={cloakSeed}
              />
            }
          />
          <Route
            path="/export"
            element={
              <ExportPage
                cloakSeed={cloakSeed}
              />
            }
          />
        </Routes>
      </main>

      {/* Notification */}
      {cloakSeed.error && (
        <div className="fixed bottom-4 right-4 max-w-sm bg-red-900/90 border border-red-700 rounded-lg p-4 text-red-100 text-sm">
          {cloakSeed.error}
        </div>
      )}
    </div>
  );
}

function CreateCipherPage({ cloakSeed, onDone }) {
  return (
    <div className="max-w-2xl">
      <h1 className="text-3xl font-bold mb-8">Create Your Cipher</h1>
      <ThemeSelector
        onSelectTheme={(theme, words) => {
          cloakSeed.setCipherFromTheme(theme);
          onDone();
        }}
        onCustomWords={(words) => {
          // Handle custom words
          const cipherMap = {};
          words.forEach((word, idx) => {
            cipherMap[word.toLowerCase()] = idx;
          });
          // TODO: Set custom cipher
          onDone();
        }}
      />
    </div>
  );
}

function GeneratePage({ cloakSeed, onNavigate }) {
  if (!cloakSeed.cipher) {
    return (
      <div className="text-center">
        <p className="mb-4 text-gray-300">No cipher created yet.</p>
        <button
          onClick={() => onNavigate('/create-cipher')}
          className="px-6 py-2 bg-blue-600 hover:bg-blue-700 rounded font-semibold"
        >
          Create Cipher First
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-4xl">
      <h1 className="text-3xl font-bold mb-8">Generate Your Cloak</h1>
      <CloakGenerator
        cipher={cloakSeed.cipher}
        selectedTheme={cloakSeed.selectedTheme}
        onGenerateNew={cloakSeed.generateNewCloak}
        onCopy={cloakSeed.copyToClipboard}
        onCreateCipher={() => {}}
        loading={cloakSeed.loading}
      />

      {cloakSeed.cloakPhrase && (
        <div className="mt-12">
          <CloakDisplay
            realSeed={cloakSeed.realSeed}
            cloakPhrase={cloakSeed.cloakPhrase}
            wallets={cloakSeed.wallets}
            onCopy={cloakSeed.copyToClipboard}
            onGenerate={cloakSeed.generateNewCloak}
            loading={cloakSeed.loading}
          />
        </div>
      )}
    </div>
  );
}

function RestorePage({ cloakSeed }) {
  return (
    <div className="max-w-4xl">
      <h1 className="text-3xl font-bold mb-8">Restore Your Wallet</h1>
      <CloakRestore
        onRestore={cloakSeed.restoreFromCloak}
        onCopy={cloakSeed.copyToClipboard}
        restoredSeed={cloakSeed.restoredSeed}
        restoredWallets={cloakSeed.restoredWallets}
        loading={cloakSeed.loading}
      />
    </div>
  );
}

function PanicPage({ cloakSeed }) {
  return (
    <div className="max-w-2xl">
      <h1 className="text-3xl font-bold mb-8">Panic Phrase</h1>
      <PanicPhrase
        cipher={cloakSeed.cipher}
        onGenerate={cloakSeed.createPanicPhrase}
        panicPhrase={cloakSeed.panicPhrase}
        panicWallets={cloakSeed.panicWallets}
        onCopy={cloakSeed.copyToClipboard}
        loading={cloakSeed.loading}
        isPremium={cloakSeed.isPremium}
      />
    </div>
  );
}

function ExportPage({ cloakSeed }) {
  return (
    <div className="max-w-2xl">
      <h1 className="text-3xl font-bold mb-8">Export Backup</h1>
      <Export
        cipher={cloakSeed.cipher}
        onExport={cloakSeed.exportCipher}
        isPremium={cloakSeed.isPremium}
      />
    </div>
  );
}

export default function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}
